```python
def check_date(year, month, day):
    # Tarkistetaan, onko vuosi yli 0
    if year <= 0:
        return False

    # Tarkistetaan, onko kuukausi oikea
    if month < 1 or month > 12:
        return False

    # Tarkistetaan, onko kuukauden päiväjärjestys oikea
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Kuukaudet, joissa on 31 päivää
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Kuukaudet, joissa on 30 päivää
        if day < 1 or day > 30:
            return False
    else:
        # Tammikuu, helmikuu, huhtikuu, toukokuu, heinäkuu, elokuu, syyskuu, marraskuu
        if day < 1 or day > 28:
            return False

    # Tarkistetaan, onko vuosi karkausvuosi
    if month == 2 and day == 29 and (year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)):
        return True

    return True
```

