def magic_square_test(n):
    # Tarkistetaan, onko n neliön koko, joka on yhtä suuri kuin neliön sivun pituus
    if n < 1:
        return False

    # Luodaan neliö, jossa kaikki sarakkeet, rivit ja diagonaalit ovat yhtä suuria
    square = [[0 for _ in range(n)] for _ in range(n)]

    # Alustetaan neliön arvot
    for i in range(n):
        for j in range(n):
            square[i][j] = (i + j) % n + 1

    # Tarkistetaan, onko neliö taikasäännön mukaista
    for i in range(n):
        # Tarkistetaan, ovatko rivit taikasäännön mukaista
        if sum(square[i]) != n * (n * n + 1) // 2:
            return False

        # Tarkistetaan, ovatko sarakkeet taikasäännön mukaista
        if sum([square[j][i] for j in range(n)]) != n * (n * n + 1) // 2:
            return False

    # Tarkistetaan, ovatko diagonaalit taikasäännön mukaista
    if sum([square[i][i] for i in range(n)]) != n * (n * n + 1) // 2:
        return False
    if sum([square[i][n - i - 1] for i in range(n)]) != n * (n * n + 1) // 2:
        return False

    # Jos kaikki ehdot täyttyvät, palautetaan True
    return True
