def find_Diff(arr):
    # Tarkistetaan, että lista on oikein muodossa
    if not isinstance(arr, list):
        raise ValueError("Syöte on oltava lista")

    # Tarkistetaan, että lista ei ole tyhjä
    if len(arr) == 0:
        raise ValueError("Lista ei voi olla tyhjä")

    # Lasketaan kaikkien lukujen esiintymisluvut
    freq = {}
    for num in arr:
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1

    # Etsitään korkein ja matalin esiintymisluku
    if len(freq) == 0:
        raise ValueError("Lista ei sisällä yhtään lukua")
    max_freq = max(freq.values())
    min_freq = min(freq.values())

    # Palautetaan korkeimman ja matalimman esiintymisluvun erotus
    return max_freq - min_freq
```

