def max_path_sum(triangle):
    # Alkutilanteessa, kun yläreunan pituus on 1, palautetaan yläreunan arvo
    if len(triangle) == 1:
        return triangle[0][0]

    # Alkutilanteessa, kun yläreunan pituus on 2, palautetaan suurin arvo
    if len(triangle) == 2:
        return max(triangle[1])

    # Alkutilanteessa, kun yläreunan pituus on 3, palautetaan suurin arvo
    if len(triangle) == 3:
        return max(max(row) for row in triangle[1:]) + triangle[0][0]

    # Muissa tapauksissa, lasketaan suurin arvo
    for i in range(len(triangle) - 2, 0, -1):
        # Kunkin rivin jokaisen arvon korvataan sen yläpuolella olevien arvojen summina
        for j in range(len(triangle[i])):
            triangle[i-1][j] += max(triangle[i][j], triangle[i][j+1])

    # Palautetaan suurin arvo
    return max(triangle[0])

