```python
def count_Odd_Squares(min_value, max_value):
    # Aluksi lasketaan neliöjäolliset lukut, jotka ovat min_value ja max_value välillä
    squares = [i**2 for i in range(int(min_value**0.5), int(max_value**0.5) + 1)]

    # Sitten lasketaan, kuinka monta kertaa kukin neliöjäollinen luku esiintyy min_value ja max_value välillä
    counts = {}
    for square in squares:
        if square >= min_value and square <= max_value:
            if square in counts:
                counts[square] += 1
            else:
                counts[square] = 1

    # Lopuksi lasketaan, kuinka monta neliöjäollista lukua on yhteensä, ja kuinka monta niistä on epäjärjestäytynyttä
    odd_squares_count = 0
    for square, count in counts.items():
        if is_prime(int(square**0.5)):
            odd_squares_count += count

    return odd_squares_count

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True
```

