```python
def multiply_int(a, b):
    # Jos yksi luvuista on nolla, tulosta nolla
    if a == 0 or b == 0:
        return 0

    # Jos molemmat luvut ovat samaan suuntaan, kertaa niitä yhdessä
    if (a > 0 and b > 0) or (a < 0 and b < 0):
        # Käytä algoritmia, joka kertaa kaksi positiivista lukua
        return multiply_positive(a, b)

    # Jos molemmat luvut ovat eri suuntaan, kertaa niitä yhdessä ja sitten käännä signaali
    else:
        # Käytä algoritmia, joka kertaa kaksi positiivista lukua
        result = multiply_positive(a, b)
        # Käännä signaali
        if (a > 0 and b < 0) or (a < 0 and b > 0):
            return -result
        else:
            return result

def multiply_positive(a, b):
    # Algoritmi, joka kertaa kaksi positiivista lukua
    result = 0
    for i in range(b):
        result += a
    return result
```

