```python
def check_Consecutive(lst):
    # Jos lista on tyhjä, se ei sisällä peräkkäisiä lukujen joukkoa
    if len(lst) == 0:
        return False

    # Jos lista sisältää vain yhden alkiota, se ei sisällä peräkkäisiä lukujen joukkoa
    if len(lst) == 1:
        return False

    # Alkion, joka on listaan lisätty viimeksi, on listaan lisätty viimeksi
    last_element = lst[-1]

    # Alkion, joka on listaan lisätty toiseksi viimeksi, on listaan lisätty toiseksi viimeksi
    second_last_element = lst[-2]

    # Jos listaan on lisätty vain kaksi alkioita, niin lista ei sisällä peräkkäisiä lukujen joukkoa
    if len(lst) == 2:
        return False

    # Jos listaan on lisätty vain kolme alkioita, niin lista sisältää peräkkäisiä lukujen joukkoa, jos erotus toiseen ja viimeiseen alkioon on yhtä suuri kuin erotus ensimmäiseen ja toiseen alkioon
    if len(lst) == 3:
        return last_element - second_last_element == lst[1] - lst[0]

    # Jos lista sisältää enemmän kuin kolme alkioita, niin lista sisältää peräkkäisiä lukujen joukkoa, jos kaikki erotukset ovat yhtä suuria
    for i in range(2, len(lst)):
        if last_element - lst[i-1] != lst[i-1] - lst[i-2]:
            return False
        last_element = lst[i-1]

    return True
