Funktio, joka laskee arvon 'a' potenssiin 'b', voidaan toteuttaa seuraavasti:

```python
def power(a, b):
    # Tarkistetaan, onko potenssi negatiivinen
    if b < 0:
        # Jos potenssi on negatiivinen, palautetaan arvo 1 / a potenssiin b
        return 1 / power(a, -b)

    # Tarkistetaan, onko potenssi nolla
    elif b == 0:
        # Jos potenssi on nolla, palautetaan arvo 1
        return 1

    # Tarkistetaan, onko potenssi yksi
    elif b == 1:
        # Jos potenssi on yksi, palautetaan arvo a
        return a

    # Tarkistetaan, onko a nolla
    elif a == 0:
        # Jos a on nolla, palautetaan arvo 0
        return 0

    # Tarkistetaan, onko a yksi
    elif a == 1:
        # Jos a on yksi, palautetaan arvo 1
        return 1

    # Jos ehtoja ei täytty, lasketaan arvo a potenssiin b käyttämällä algoritmiä
    else:
        # Algoritmi: a potenssiin b = (a potenssiin b/2) * (a potenssiin b/2) * (jos b on parillinen) tai
        # a potenssiin b = a * (a potenssiin (b-1)) (jos b on joustava)
        if b % 2 == 0:
            # Jos b on parillinen, lasketaan arvo a potenssiin b/2 kaksi kertaa
            return power(a, b // 2) * power(a, b // 2)
        else:
            # Jos b on joustava, lasketaan arvo a potenssiin (b-1) ja kertaa sen a:lla
            return a * power(a, b - 1)
