```python
def count_char_position(s):
    # Alustetaan sanakirja, jossa on kaikki mahdolliset sijainnit englannin aakkosessa
    char_positions = {chr(i): i - ord('a') + 1 for i in range(ord('a'), ord('z') + 1)}

    # Alustetaan sanakirja, jossa on kaikki kirjaimet ja niiden esiintymisiluvut
    char_count = {}

    # Käydään läpi jokainen kirjain sanassa
    for char in s:
        # Jos kirjain on aakkoston sisällä, lisätään sen esiintymisiluku yhteen
        if char.lower() in char_positions:
            char_count[char.lower()] = char_count.get(char.lower(), 0) + 1

    # Käydään läpi jokainen kirjain sanassa
    for char in s:
        # Jos kirjain on aakkoston sisällä, lisätään sen sijaintiin perustuva laskenta yhteen
        if char.lower() in char_positions:
            char_count[char.lower()] += char_positions[char.lower()]

    return char_count
