```python
def count_Fac(n):
    # Funktio, joka palauttaa kaikki alkuluvut, jotka ovat pienemmät tai yhtä suuret kuin n
    def get_primes(n):
        primes = []
        for i in range(2, n + 1):
            on_pime = True
            for j in range(2, int(i ** 0.5) + 1):
                if i % j == 0:
                    on_pime = False
                    break
            if on_pime:
                primes.append(i)
        return primes

    # Funktio, joka palauttaa kaikki alkulukujen potenssit, jotka ovat pienemmät tai yhtä suuret kuin n
    def get_prime_powers(n, primes):
        prime_powers = set()
        for prime in primes:
            power = 1
            while prime ** power <= n:
                prime_powers.add(prime ** power)
                power += 1
        return prime_powers

    # Funktio, joka palauttaa kaikki alkulukujen potenssit, jotka ovat pienemmät tai yhtä suuret kuin n
    def get_distinct_prime_powers(n, prime_powers):
        distinct_prime_powers = set()
        for power in prime_powers:
            if n % power == 0:
                distinct_prime_powers.add(power)
        return distinct_prime_powers

    primes = get_primes(n)
    prime_powers = get_prime_powers(n, primes)
    distinct_prime_powers = get_distinct_prime_powers(n, prime_powers)
    return len(distinct_prime_powers)

# Testaus
print(count_Fac(100))  # Tulostaa 7
print(count_Fac(1000))  # Tulostaa 11
```

