```python
def breakSum(n):
    # Jos luku on 0 tai negatiivinen, palautetaan 0, koska ei ole mahdollista jakaa sitä
    if n <= 0:
        return 0

    # Jos luku on 1, palautetaan 1, koska se on yksittäinen osa
    if n == 1:
        return 1

    # Muussa tapauksessa, etsitään maksimiarvo, joka saadaan jakamalla luku kolmeen osaan
    # ja summaamalla ne yhteen
    else:
        # Käytetään dynaamista ohjelmointia, jossa kutsutaan itseään toistuvasti
        # ja tallennetaan arvot, jotta ne ei tarvitse lasketa uudelleen
        memo = {}

        def breakSumDynaamisesti(n):
            # Jos luku on jo arvottu, palautetaan tallennettu arvo
            if n in memo:
                return memo[n]

            # Jos luku on 0 tai negatiivinen, palautetaan 0
            if n <= 0:
                return 0

            # Jos luku on 1, palautetaan 1
            if n == 1:
                return 1

            # Muussa tapauksessa, etsitään maksimiarvo, joka saadaan jakamalla luku kolmeen osaan
            # ja summaamalla ne yhteen
            else:
                # Käytetään dynaamista ohjelmointia, jossa kutsutaan itseään toistuvasti
                # ja tallennetaan arvot, jotta ne ei tarvitse lasketa uudelleen
                for i in range(1, n):
                    # Kutsutaan itseään toistuvasti ja tallennetaan arvo
                    memo[i] = breakSumDynaamisesti(i)
                    memo[n-i] = breakSumDynaamisesti(n-i)

                # Palautetaan maksimiarvo, joka saadaan jakamalla luku kolmeen osaan
                # ja summaamalla ne yhteen
                return max(memo[i] + memo[n-i] + i for i in range(1, n))

        # Kutsutaan dynaamista funktiota ja palautetaan arvo
        return breakSumDynaamisesti(n)

# Testataan funktiota
